{
  "name": "nbench-solar-system",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "scripts": {
    "preprocess": "node scripts/preprocess.js",
    "dev": "vite",
    "build": "pnpm run preprocess && vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "three": "^0.160.0"
  },
  "devDependencies": {
    "@types/three": "^0.160.0",
    "typescript": "^5.3.3",
    "vite": "^5.0.12"
  }
}

import fs from 'fs';
import path from 'path';

const DATA_DIR = './data';
const OUT_DIR = './public/data';

console.log('Starting data pre-processing...');

// 1. Planets
const planetsRaw = fs.readFileSync(path.join(DATA_DIR, 'planets.json'), 'utf8');
fs.writeFileSync(path.join(OUT_DIR, 'planets.json'), JSON.stringify(JSON.parse(planetsRaw)));
console.log('✔ Copied planets.json');

// 2. Asteroids
console.log('Loading asteroids.json...');
const asteroidsRaw = fs.readFileSync(path.join(DATA_DIR, 'asteroids.json'), 'utf8');
const asteroids = JSON.parse(asteroidsRaw);

const asteroidFields = [
  "pdes", "name", "full_name", "class", "a", "e", "i", "om", "w", "ma", 
  "epoch", "per", "neo", "pha", "moid", "H", "diameter"
];

const processedAsteroids = asteroids.map(ast => {
  return [
    ast.pdes || '',
    ast.name || null,
    ast.full_name || '',
    ast.class || '',
    ast.a !== undefined && ast.a !== null ? Number(ast.a) : null,
    ast.e !== undefined && ast.e !== null ? Number(ast.e) : null,
    ast.i !== undefined && ast.i !== null ? Number(ast.i) : null,
    ast.om !== undefined && ast.om !== null ? Number(ast.om) : null,
    ast.w !== undefined && ast.w !== null ? Number(ast.w) : null,
    ast.ma !== undefined && ast.ma !== null ? Number(ast.ma) : null,
    ast.epoch !== undefined && ast.epoch !== null ? Number(ast.epoch) : null,
    ast.per !== undefined && ast.per !== null ? Number(ast.per) : null,
    ast.neo ? 1 : 0,
    ast.pha ? 1 : 0,
    ast.moid !== undefined && ast.moid !== null ? Number(ast.moid) : null,
    ast.H !== undefined && ast.H !== null ? Number(ast.H) : null,
    ast.diameter !== undefined && ast.diameter !== null ? Number(ast.diameter) : null
  ];
});

fs.writeFileSync(
  path.join(OUT_DIR, 'asteroids_opt.json'), 
  JSON.stringify({ fields: asteroidFields, data: processedAsteroids })
);
console.log(`✔ Processed ${processedAsteroids.length} asteroids to asteroids_opt.json`);

// 3. Comets
console.log('Loading comets.json...');
const cometsRaw = fs.readFileSync(path.join(DATA_DIR, 'comets.json'), 'utf8');
const comets = JSON.parse(cometsRaw);

const cometFields = [
  "pdes", "name", "full_name", "class", "e", "a", "q", "i", "om", "w",
  "ma", "tp", "per", "n", "epoch", "M1", "diameter"
];

const processedComets = comets.map(cmt => {
  return [
    cmt.pdes || '',
    cmt.name || null,
    cmt.full_name || '',
    cmt.class || '',
    cmt.e !== undefined && cmt.e !== null ? Number(cmt.e) : null,
    cmt.a !== undefined && cmt.a !== null ? Number(cmt.a) : null,
    cmt.q !== undefined && cmt.q !== null ? Number(cmt.q) : null,
    cmt.i !== undefined && cmt.i !== null ? Number(cmt.i) : null,
    cmt.om !== undefined && cmt.om !== null ? Number(cmt.om) : null,
    cmt.w !== undefined && cmt.w !== null ? Number(cmt.w) : null,
    cmt.ma !== undefined && cmt.ma !== null ? Number(cmt.ma) : null,
    cmt.tp !== undefined && cmt.tp !== null ? Number(cmt.tp) : null,
    cmt.per !== undefined && cmt.per !== null ? Number(cmt.per) : null,
    cmt.n !== undefined && cmt.n !== null ? Number(cmt.n) : null,
    cmt.epoch !== undefined && cmt.epoch !== null ? Number(cmt.epoch) : null,
    cmt.M1 !== undefined && cmt.M1 !== null ? Number(cmt.M1) : null,
    cmt.diameter !== undefined && cmt.diameter !== null ? Number(cmt.diameter) : null
  ];
});

fs.writeFileSync(
  path.join(OUT_DIR, 'comets_opt.json'),
  JSON.stringify({ fields: cometFields, data: processedComets })
);
console.log(`✔ Processed ${processedComets.length} comets to comets_opt.json`);

// 4. Sentry (Impact risk summary)
console.log('Loading sentry.json...');
const sentryRaw = fs.readFileSync(path.join(DATA_DIR, 'sentry.json'), 'utf8');
const sentryList = JSON.parse(sentryRaw);

const sentryMap = {};
sentryList.forEach(s => {
  if (s.des) {
    sentryMap[s.des] = {
      ip: s.ip !== undefined && s.ip !== null ? Number(s.ip) : null,
      ps_cum: s.ps_cum !== undefined && s.ps_cum !== null ? Number(s.ps_cum) : null,
      ts_max: s.ts_max !== undefined && s.ts_max !== null ? Number(s.ts_max) : null,
      range: s.range || '',
      n_imp: s.n_imp !== undefined && s.n_imp !== null ? Number(s.n_imp) : null,
      diameter: s.diameter !== undefined && s.diameter !== null ? Number(s.diameter) : null,
      h: s.h !== undefined && s.h !== null ? Number(s.h) : null,
      v_inf: s.v_inf !== undefined && s.v_inf !== null ? Number(s.v_inf) : null
    };
  }
});

fs.writeFileSync(path.join(OUT_DIR, 'sentry_opt.json'), JSON.stringify(sentryMap));
console.log(`✔ Processed ${sentryList.length} sentry entries to sentry_opt.json`);

// 5. Close Approaches
console.log('Loading close-approaches.json...');
const caRaw = fs.readFileSync(path.join(DATA_DIR, 'close-approaches.json'), 'utf8');
const caList = JSON.parse(caRaw);

const caMap = {};
caList.forEach(ca => {
  if (ca.des) {
    if (!caMap[ca.des]) {
      caMap[ca.des] = [];
    }
    caMap[ca.des].push([
      ca.jd !== undefined && ca.jd !== null ? Number(ca.jd) : null,
      ca.cd || '',
      ca.dist !== undefined && ca.dist !== null ? Number(ca.dist) : null,
      ca.v_rel !== undefined && ca.v_rel !== null ? Number(ca.v_rel) : null,
      ca.h !== undefined && ca.h !== null ? Number(ca.h) : null
    ]);
  }
});

// Sort close approaches for each object by jd ascending
for (const des in caMap) {
  caMap[des].sort((a, b) => a[0] - b[0]);
}

fs.writeFileSync(path.join(OUT_DIR, 'close_approaches_opt.json'), JSON.stringify(caMap));
console.log(`✔ Processed ${caList.length} close approaches for ${Object.keys(caMap).length} objects to close_approaches_opt.json`);

console.log('Data pre-processing completed successfully!');

import { defineConfig } from 'vite';

export default defineConfig({
  base: './', // Use relative paths for assets so it can run inside an iframe
  build: {
    outDir: 'dist',
    minify: 'esbuild',
    sourcemap: false,
    assetsInlineLimit: 4096, // Inline small assets if any
  },
  server: {
    port: 3000,
    open: false,
  }
});

import * as THREE from 'three';

export interface OrbitalElements {
  pdes: string;
  name: string | null;
  full_name: string;
  class: string;
  a: number | null;
  e: number;
  i: number;
  om: number;
  w: number;
  ma: number | null;
  epoch: number | null;
  per: number | null;
  tp: number | null;
  n: number | null;
  q?: number | null;
  M1?: number | null;
  diameter: number | null;
}

const GAUSSIAN_K = 0.01720209895; // Gaussian gravitational constant

/**
 * Converts a standard JavaScript Date object to Julian Date.
 */
export function dateToJulianDate(date: Date): number {
  return 2440587.5 + date.getTime() / 86400000;
}

/**
 * Converts a Julian Date to a standard JavaScript Date object.
 */
export function julianDateToDate(jd: number): Date {
  return new Date((jd - 2440587.5) * 86400000);
}

/**
 * Formats Julian Date to a human readable UTC string.
 */
export function formatJulianDate(jd: number): string {
  const date = julianDateToDate(jd);
  return date.toUTCString().replace(' GMT', ' UTC');
}

/**
 * Solves Kepler's equation for elliptical orbits: E - e * sin(E) = M
 * @param M Mean anomaly in radians
 * @param e Eccentricity (e < 1)
 */
function solveKeplerElliptical(M: number, e: number): number {
  let E = M;
  const tol = 1e-6;
  for (let k = 0; k < 12; k++) {
    const diff = E - e * Math.sin(E) - M;
    if (Math.abs(diff) < tol) break;
    E = E - diff / (1.0 - e * Math.cos(E));
  }
  return E;
}

/**
 * Solves Kepler's equation for hyperbolic orbits: e * sinh(F) - F = N
 * @param N Mean anomaly in radians
 * @param e Eccentricity (e > 1)
 */
function solveKeplerHyperbolic(N: number, e: number): number {
  // Good starting approximation
  let F = N;
  if (N > 0) {
    F = Math.log(2 * N / e + 1.0);
  } else if (N < 0) {
    F = -Math.log(-2 * N / e + 1.0);
  }

  const tol = 1e-6;
  for (let k = 0; k < 15; k++) {
    const diff = e * Math.sinh(F) - F - N;
    if (Math.abs(diff) < tol) break;
    F = F - diff / (e * Math.cosh(F) - 1.0);
  }
  return F;
}

/**
 * Solves Barker's equation for parabolic or near-parabolic orbits:
 * tan(v/2) + (1/3)*tan^3(v/2) = B
 * Returns tan(v/2)
 */
function solveBarker(B: number): number {
  const threeBOver2 = 1.5 * B;
  const rad = Math.sqrt(1.0 + threeBOver2 * threeBOver2);
  return Math.cbrt(threeBOver2 + rad) - Math.cbrt(-threeBOver2 + rad);
}

/**
 * Rotates orbital-plane coordinates (x', y', 0) to J2000 heliocentric ecliptic coordinates.
 */
export function rotateToEcliptic(
  xPrime: number, 
  yPrime: number, 
  iDeg: number, 
  omDeg: number, 
  wDeg: number
): THREE.Vector3 {
  const iRad = iDeg * Math.PI / 180;
  const omRad = omDeg * Math.PI / 180;
  const wRad = wDeg * Math.PI / 180;

  const cosOm = Math.cos(omRad);
  const sinOm = Math.sin(omRad);
  const cosW = Math.cos(wRad);
  const sinW = Math.sin(wRad);
  const cosI = Math.cos(iRad);
  const sinI = Math.sin(iRad);

  const px = cosW * cosOm - sinW * sinOm * cosI;
  const py = cosW * sinOm + sinW * cosOm * cosI;
  const pz = sinW * sinI;

  const qx = -sinW * cosOm - cosW * sinOm * cosI;
  const qy = -sinW * sinOm + cosW * cosOm * cosI;
  const qz = cosW * sinI;

  const x = xPrime * px + yPrime * qx;
  const y = xPrime * py + yPrime * qy;
  const z = xPrime * pz + yPrime * qz;

  return new THREE.Vector3(x, y, z);
}

/**
 * Computes 3D position of an object from its orbital elements at a specific Julian Date.
 * Units are in AU.
 */
export function propagateOrbit(body: OrbitalElements, jd: number): THREE.Vector3 {
  const e = body.e;
  const i = body.i;
  const om = body.om;
  const w = body.w;

  // 1. Parabolic / near-parabolic orbits (e.g. e >= 0.999 and e <= 1.001) or comets without a semi-major axis
  if (e >= 0.999 && e <= 1.001) {
    const q = body.q || (body.a ? body.a * (1 - e) : null);
    if (!q) return new THREE.Vector3(0, 0, 0); // fallback

    const tp = body.tp || jd;
    const deltaT = jd - tp;

    // Barker's equation parameter B
    const B = (GAUSSIAN_K / (Math.sqrt(2) * Math.pow(q, 1.5))) * deltaT;
    const tanVOver2 = solveBarker(B);
    const r = q * (1.0 + tanVOver2 * tanVOver2);

    const xPrime = q * (1.0 - tanVOver2 * tanVOver2);
    const yPrime = 2 * q * tanVOver2;

    return rotateToEcliptic(xPrime, yPrime, i, om, w);
  }

  // 2. Hyperbolic orbits (e > 1)
  if (e > 1.001) {
    const q = body.q || (body.a ? Math.abs(body.a) * (e - 1) : null);
    if (!q) return new THREE.Vector3(0, 0, 0); // fallback

    // semi-major axis is negative for hyperbolas
    const a = body.a !== null && body.a < 0 ? body.a : -q / (e - 1);
    const absA = Math.abs(a);

    const tp = body.tp || jd;
    const deltaT = jd - tp;

    // Hyperbolic mean motion n (radians/day)
    const nRad = GAUSSIAN_K / Math.pow(absA, 1.5);
    const N = nRad * deltaT;

    const F = solveKeplerHyperbolic(N, e);

    const xPrime = a * (Math.cosh(F) - e);
    const yPrime = absA * Math.sqrt(e * e - 1.0) * Math.sinh(F);

    return rotateToEcliptic(xPrime, yPrime, i, om, w);
  }

  // 3. Elliptical orbits (e < 0.999)
  const a = body.a;
  if (a === null || a <= 0) return new THREE.Vector3(0, 0, 0); // fallback

  const epoch = body.epoch || 2451545.0; // Default to J2000
  const deltaT = jd - epoch;

  // Compute mean motion n in degrees/day
  let n = body.n;
  if (n === null || n === undefined) {
    if (body.per) {
      n = 360.0 / body.per;
    } else {
      n = 0.9856076686 / Math.pow(a, 1.5); // Derivation from Kepler's 3rd law
    }
  }

  // Compute mean anomaly at time t
  const ma0 = body.ma || 0;
  const M = (ma0 + n * deltaT) % 360;
  const MRad = M * Math.PI / 180;

  // Solve Kepler's equation for E
  const E = solveKeplerElliptical(MRad, e);

  // Compute positions in orbital plane
  const xPrime = a * (Math.cos(E) - e);
  const yPrime = a * Math.sqrt(1.0 - e * e) * Math.sin(E);

  return rotateToEcliptic(xPrime, yPrime, i, om, w);
}

/**
 * Computes a list of 3D points representing the orbital path.
 * This is used for rendering the orbit path in the scene.
 */
export function getOrbitPathPoints(body: OrbitalElements, numPoints: number = 180): THREE.Vector3[] {
  const points: THREE.Vector3[] = [];
  const e = body.e;
  const i = body.i;
  const om = body.om;
  const w = body.w;

  // Elliptical Orbit: Draw full ellipse by stepping Eccentric Anomaly E from 0 to 2PI
  if (e < 0.999) {
    const a = body.a;
    if (a === null || a <= 0) return [];

    for (let k = 0; k <= numPoints; k++) {
      const E = (k / numPoints) * 2 * Math.PI;
      const xPrime = a * (Math.cos(E) - e);
      const yPrime = a * Math.sqrt(1.0 - e * e) * Math.sin(E);
      points.push(rotateToEcliptic(xPrime, yPrime, i, om, w));
    }
    return points;
  }

  // Hyperbolic Orbit: Draw curve by stepping F from -2.0 to 2.0
  if (e > 1.001) {
    const q = body.q || (body.a ? Math.abs(body.a) * (e - 1) : null);
    if (!q) return [];
    const a = body.a !== null && body.a < 0 ? body.a : -q / (e - 1);
    const absA = Math.abs(a);

    // Limit F range so the path doesn't go off to infinity too quickly
    const maxF = 2.2;
    for (let k = 0; k <= numPoints; k++) {
      const F = -maxF + (k / numPoints) * (2 * maxF);
      const xPrime = a * (Math.cosh(F) - e);
      const yPrime = absA * Math.sqrt(e * e - 1.0) * Math.sinh(F);
      points.push(rotateToEcliptic(xPrime, yPrime, i, om, w));
    }
    return points;
  }

  // Parabolic Orbit: Draw curve by stepping tan(v/2) from -2.5 to 2.5
  const q = body.q || (body.a ? body.a * (1 - e) : null);
  if (!q) return [];

  const maxTan = 2.5;
  for (let k = 0; k <= numPoints; k++) {
    const tanVOver2 = -maxTan + (k / numPoints) * (2 * maxTan);
    const xPrime = q * (1.0 - tanVOver2 * tanVOver2);
    const yPrime = 2 * q * tanVOver2;
    points.push(rotateToEcliptic(xPrime, yPrime, i, om, w));
  }
  return points;
}

:root {
  --bg-color: #05070c;
  --bg-panel: rgba(10, 15, 26, 0.85);
  --bg-panel-solid: #0c1220;
  --border-color: rgba(56, 189, 248, 0.2);
  --border-focus: rgba(56, 189, 248, 0.6);
  --text-primary: #f0f7ff;
  --text-secondary: #94a3b8;
  --accent-color: #38bdf8; /* sky-400 */
  --accent-hover: #0ea5e9; /* sky-500 */
  --hazard-color: #f43f5e; /* rose-500 */
  --comet-color: #22c55e; /* green-500 */
  --font-family: 'Inter', system-ui, -apple-system, sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;
  --transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body, html {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background-color: var(--bg-color);
  color: var(--text-primary);
  font-family: var(--font-family);
  user-select: none;
}

#canvas-container {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 1;
}

/* UI Overlays */
.overlay {
  position: absolute;
  z-index: 10;
  pointer-events: none;
}

.overlay * {
  pointer-events: auto;
}

/* Glassmorphism Panel style */
.panel {
  background: var(--bg-panel);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.5);
  display: flex;
  flex-direction: column;
}

/* Top Left: Header and Stats */
.header-panel {
  top: 20px;
  left: 20px;
  width: 340px;
  padding: 16px;
}

.header-panel h1 {
  font-size: 1.2rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--accent-color);
  margin-bottom: 4px;
}

.header-panel .subtitle {
  font-size: 0.8rem;
  color: var(--text-secondary);
  margin-bottom: 12px;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 8px;
  font-size: 0.75rem;
  border-top: 1px solid var(--border-color);
  padding-top: 10px;
}

.stat-item {
  display: flex;
  flex-direction: column;
}

.stat-label {
  color: var(--text-secondary);
  font-size: 0.7rem;
}

.stat-val {
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: 0.95rem;
}

/* Right Side: Filters, Search, Object List */
.sidebar-panel {
  top: 20px;
  right: 20px;
  bottom: 130px;
  width: 360px;
  padding: 16px;
  max-height: calc(100% - 170px);
}

.tab-buttons {
  display: flex;
  margin-bottom: 12px;
  border-bottom: 1px solid var(--border-color);
}

.tab-btn {
  flex: 1;
  background: none;
  border: none;
  color: var(--text-secondary);
  padding: 8px;
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  border-bottom: 2px solid transparent;
}

.tab-btn.active {
  color: var(--accent-color);
  border-bottom-color: var(--accent-color);
}

.tab-content {
  flex: 1;
  overflow-y: auto;
  display: none;
  flex-direction: column;
  gap: 12px;
}

.tab-content.active {
  display: flex;
}

/* Forms and Inputs */
.form-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.form-group label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.02em;
}

.search-input-wrapper {
  position: relative;
}

.search-input {
  width: 100%;
  background: rgba(0, 0, 0, 0.4);
  border: 1px solid var(--border-color);
  color: var(--text-primary);
  padding: 8px 12px;
  border-radius: 4px;
  font-size: 0.85rem;
  outline: none;
  transition: var(--transition);
}

.search-input:focus {
  border-color: var(--border-focus);
  box-shadow: 0 0 8px rgba(56, 189, 248, 0.3);
}

.select-input {
  width: 100%;
  background: var(--bg-panel-solid);
  border: 1px solid var(--border-color);
  color: var(--text-primary);
  padding: 8px;
  border-radius: 4px;
  font-size: 0.85rem;
  outline: none;
  cursor: pointer;
}

.select-input:focus {
  border-color: var(--border-focus);
}

.checkbox-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-top: 4px;
}

.checkbox-label {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.8rem;
  color: var(--text-primary);
  cursor: pointer;
}

.checkbox-label input {
  cursor: pointer;
  accent-color: var(--accent-color);
}

.slider-wrapper {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.slider-header {
  display: flex;
  justify-content: space-between;
  font-size: 0.75rem;
}

.slider-val {
  font-family: var(--font-mono);
  color: var(--accent-color);
}

input[type="range"] {
  width: 100%;
  accent-color: var(--accent-color);
  background: rgba(255, 255, 255, 0.1);
  height: 4px;
  border-radius: 2px;
  outline: none;
  cursor: pointer;
}

/* Object list formatting */
.object-list {
  flex: 1;
  overflow-y: auto;
  border: 1px solid var(--border-color);
  border-radius: 4px;
  background: rgba(0, 0, 0, 0.3);
  display: flex;
  flex-direction: column;
}

.object-item {
  padding: 8px 12px;
  border-bottom: 1px solid rgba(56, 189, 248, 0.1);
  font-size: 0.8rem;
  cursor: pointer;
  display: flex;
  justify-content: space-between;
  align-items: center;
  transition: var(--transition);
}

.object-item:hover {
  background: rgba(56, 189, 248, 0.08);
}

.object-item.selected {
  background: rgba(56, 189, 248, 0.15);
  border-left: 3px solid var(--accent-color);
}

.object-item-name {
  font-weight: 500;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 180px;
}

.object-item-meta {
  font-family: var(--font-mono);
  font-size: 0.7rem;
  color: var(--text-secondary);
  display: flex;
  gap: 6px;
  align-items: center;
}

.badge {
